mapper.select:
select
       tjdate,
       areaflag,
       codecname,
       coalesce(bal_lj, 0)          as bal_lj,
       sumestipaid / 10000.0         as sumestipaid,
       coalesce(ja_lj, 0)            as ja_lj,
       sumpaid_lj / 10000.0          as sumpaid_lj,
       cast(coalesce(bal_dr, 0) as varchar(50))        as bal_dr,
       cast(coalesce(sumestipaid_dr, 0) as varchar(50)) as sumestipaid_dr
from acd_shuiyanche_cld_hz
where areaflag = #{areaflag}
  and codecname = #{codecname}
  and tjdate = (
      select max(tjdate) from acd_shuiyanche_cld_hz
      where areaflag = #{areaflag}
        and codecname = #{codecname}
        and tjdate <= #{today}
  )
